#include<bits/stdc++.h>
using namespace std;
vector<int> graph[100005];
int vis[100005];
int n,m;
void dfs(int x){
	cout<<x<<" ";
	for(auto i:graph[x]){
	//	cout<<i<<" ";
		if(!vis[i]){
			vis[i]=1;
			dfs(i);
		}
	}
}
void bfs(int st){
	queue<int>q;
	q.push(st);
	while(q.size()){
		int x=q.front();
		q.pop();
		cout<<x<<" ";
		for(auto i:graph[x]){
			if(!vis[i]){
				q.push(i);
				vis[i]=1;
			}
		}
	}
}
int main()
{
	cin>>n>>m;
	for(int i=0;i<m;i++){
		int u,v;
		cin>>u>>v;
		graph[u].push_back(v);
	}
	for(int i=1;i<=n;i++){
		sort(graph[i].begin(),graph[i].end());
	}
	vis[1]=1;
	dfs(1);
	memset(vis,0,sizeof(vis));
	vis[1]=1;
	cout<<endl;
	bfs(1);
}
